#include <bits/stdc++.h>
using namespace std;
int k,l,d;
string t;
int main()
{
    cin>>k;
    for (int i=0;i<k;i++){
        cin>>t[i];
        l=t[i].length();
        int n=0,m=0;
        for (int j=0;j<l-2;j++){
            if (t[i][j]=='L'&&t[i][j+1]=='G'&&t[i][j+2]=='R') n++;
            if (t[i][j]=='C'&&t[i][j+1]=='S'&&t[i][j+2]=='P') m++;
        }
        d=min(n,m);
        if (d==0) cout<<"0"<<endl;
        else if (d==1) cout<<"1"<<endl;
        else cout<<d/2<<endl;
    }
    return 0;
}
